            setSelectedChurchId(churches[0].id);
        } else {
            setSelectedChurchId('');
        }
    }, [churches, manualIdentificationTx, bulkIdentificationTxs]);


    if (!manualIdentificationTx && !bulkIdentificationTxs) return null;

